import{_ as e,o as l,c as d,ae as a}from"./chunks/framework.BEtfQoF7.js";const g=JSON.parse('{"title":"도구 레퍼런스","description":"권한 요구사항을 포함한 Claude Code가 사용할 수 있는 도구들의 완전한 레퍼런스","frontmatter":{"title":"도구 레퍼런스","description":"권한 요구사항을 포함한 Claude Code가 사용할 수 있는 도구들의 완전한 레퍼런스"},"headers":[],"relativePath":"tools-reference.md","filePath":"tools-reference.md","lastUpdated":1776205703000}'),o={name:"tools-reference.md"};function s(i,t,c,r,n,h){return l(),d("div",null,[...t[0]||(t[0]=[a(`<h1 id="도구-레퍼런스" tabindex="-1">도구 레퍼런스 <a class="header-anchor" href="#도구-레퍼런스" aria-label="Permalink to &quot;도구 레퍼런스&quot;">​</a></h1><blockquote><p>Claude Code가 사용할 수 있는 도구들과 권한 요구사항에 대한 완전한 레퍼런스입니다.</p></blockquote><p>Claude Code는 코드베이스를 이해하고 수정하는 데 도움이 되는 내장 도구 세트를 제공합니다. 도구 이름은 <a href="/claude-code-docs-ko/permissions.html#tool-specific-permission-rules">권한 규칙</a>, <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트 도구 목록</a>, <a href="/claude-code-docs-ko/hooks.html">훅 매처</a>에서 사용하는 정확한 문자열입니다. 도구를 완전히 비활성화하려면 <a href="/claude-code-docs-ko/permissions.html#tool-specific-permission-rules">권한 설정</a>의 <code>deny</code> 배열에 도구 이름을 추가하세요.</p><p>커스텀 도구를 추가하려면 <a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>를 연결하세요. 재사용 가능한 프롬프트 기반 워크플로우로 Claude를 확장하려면 <a href="/claude-code-docs-ko/skills.html">스킬</a>을 작성하세요. 스킬은 새 도구 항목을 추가하는 대신 기존 <code>Skill</code> 도구를 통해 실행됩니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">도구</th><th style="text-align:left;">설명</th><th style="text-align:left;">권한 필요 여부</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Agent</code></td><td style="text-align:left;">작업을 처리하기 위해 자체 컨텍스트 창을 가진 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>를 생성합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>AskUserQuestion</code></td><td style="text-align:left;">요구사항 수집이나 모호함 해소를 위해 객관식 질문을 합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Bash</code></td><td style="text-align:left;">환경에서 셸 명령을 실행합니다. <a href="#bash-도구-동작">Bash 도구 동작</a> 참조</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>CronCreate</code></td><td style="text-align:left;">현재 세션 내에서 반복 또는 일회성 프롬프트를 예약합니다 (Claude 종료 시 삭제됨). <a href="/claude-code-docs-ko/scheduled-tasks.html">예약된 작업</a> 참조</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>CronDelete</code></td><td style="text-align:left;">ID로 예약된 작업을 취소합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>CronList</code></td><td style="text-align:left;">세션의 모든 예약된 작업을 나열합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Edit</code></td><td style="text-align:left;">특정 파일에 대한 타겟 편집을 수행합니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>EnterPlanMode</code></td><td style="text-align:left;">코딩 전에 접근 방식을 설계하기 위해 플랜 모드로 전환합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>EnterWorktree</code></td><td style="text-align:left;">격리된 <a href="/claude-code-docs-ko/common-workflows.html#run-parallel-claude-code-sessions-with-git-worktrees">git worktree</a>를 생성하고 전환합니다. <code>path</code>를 전달하면 새로 생성하는 대신 현재 저장소의 기존 worktree로 전환합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>ExitPlanMode</code></td><td style="text-align:left;">승인을 위한 계획을 제시하고 플랜 모드를 종료합니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>ExitWorktree</code></td><td style="text-align:left;">worktree 세션을 종료하고 원래 디렉토리로 돌아갑니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Glob</code></td><td style="text-align:left;">패턴 매칭을 기반으로 파일을 찾습니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Grep</code></td><td style="text-align:left;">파일 내용에서 패턴을 검색합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>ListMcpResourcesTool</code></td><td style="text-align:left;">연결된 <a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>가 노출하는 리소스를 나열합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>LSP</code></td><td style="text-align:left;">언어 서버를 통한 코드 인텔리전스: 정의로 이동, 참조 찾기, 타입 오류 및 경고 보고. <a href="#lsp-도구-동작">LSP 도구 동작</a> 참조</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Monitor</code></td><td style="text-align:left;">백그라운드에서 명령을 실행하고 각 출력 줄을 Claude에 전달하여 대화 중에 로그 항목, 파일 변경, 폴링된 상태에 반응할 수 있게 합니다. <a href="#monitor-도구">Monitor 도구</a> 참조</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>NotebookEdit</code></td><td style="text-align:left;">Jupyter 노트북 셀을 수정합니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>PowerShell</code></td><td style="text-align:left;">Windows에서 PowerShell 명령을 실행합니다. 옵트인 프리뷰. <a href="#powershell-도구">PowerShell 도구</a> 참조</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>Read</code></td><td style="text-align:left;">파일 내용을 읽습니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>ReadMcpResourceTool</code></td><td style="text-align:left;">URI로 특정 MCP 리소스를 읽습니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>SendMessage</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/agent-teams.html">에이전트 팀</a> 팀원에게 메시지를 보내거나 에이전트 ID로 <a href="/claude-code-docs-ko/sub-agents.html#resume-subagents">서브에이전트를 재개</a>합니다. 중지된 서브에이전트는 백그라운드에서 자동으로 재개됩니다. <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1</code> 설정 시에만 사용 가능</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>Skill</code></td><td style="text-align:left;">메인 대화 내에서 <a href="/claude-code-docs-ko/skills.html#control-who-invokes-a-skill">스킬</a>을 실행합니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>TaskCreate</code></td><td style="text-align:left;">작업 목록에 새 작업을 생성합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TaskGet</code></td><td style="text-align:left;">특정 작업의 전체 상세 정보를 가져옵니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TaskList</code></td><td style="text-align:left;">현재 상태와 함께 모든 작업을 나열합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TaskOutput</code></td><td style="text-align:left;">(더 이상 사용되지 않음) 백그라운드 작업의 출력을 가져옵니다. 작업 출력 파일 경로에서 <code>Read</code>를 사용하는 것이 권장됩니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TaskStop</code></td><td style="text-align:left;">ID로 실행 중인 백그라운드 작업을 종료합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TaskUpdate</code></td><td style="text-align:left;">작업 상태, 의존성, 상세 정보를 업데이트하거나 작업을 삭제합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TeamCreate</code></td><td style="text-align:left;">여러 팀원으로 구성된 <a href="/claude-code-docs-ko/agent-teams.html">에이전트 팀</a>을 생성합니다. <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1</code> 설정 시에만 사용 가능</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TeamDelete</code></td><td style="text-align:left;">에이전트 팀을 해산하고 팀원 프로세스를 정리합니다. <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1</code> 설정 시에만 사용 가능</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>TodoWrite</code></td><td style="text-align:left;">세션 작업 체크리스트를 관리합니다. 비대화형 모드와 <a href="/claude-code-docs-ko/headless.html">Agent SDK</a>에서 사용 가능하며, 대화형 세션에서는 TaskCreate, TaskGet, TaskList, TaskUpdate를 대신 사용합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>ToolSearch</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/mcp.html#scale-with-mcp-tool-search">도구 검색</a>이 활성화된 경우 지연 로드된 도구를 검색하고 로드합니다</td><td style="text-align:left;">아니오</td></tr><tr><td style="text-align:left;"><code>WebFetch</code></td><td style="text-align:left;">지정된 URL에서 콘텐츠를 가져옵니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>WebSearch</code></td><td style="text-align:left;">웹 검색을 수행합니다</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;"><code>Write</code></td><td style="text-align:left;">파일을 생성하거나 덮어씁니다</td><td style="text-align:left;">예</td></tr></tbody></table><p>권한 규칙은 <code>/permissions</code>를 사용하거나 <a href="/claude-code-docs-ko/settings.html#available-settings">권한 설정</a>에서 구성할 수 있습니다. <a href="/claude-code-docs-ko/permissions.html#tool-specific-permission-rules">도구별 권한 규칙</a>도 참조하세요.</p><h2 id="bash-도구-동작" tabindex="-1">Bash 도구 동작 <a class="header-anchor" href="#bash-도구-동작" aria-label="Permalink to &quot;Bash 도구 동작&quot;">​</a></h2><p>Bash 도구는 다음과 같은 지속성 동작으로 각 명령을 별도의 프로세스에서 실행합니다:</p><ul><li>Claude가 메인 세션에서 <code>cd</code>를 실행하면, 새 작업 디렉토리는 프로젝트 디렉토리 또는 <code>--add-dir</code>, <code>/add-dir</code>, 또는 설정의 <code>additionalDirectories</code>로 추가한 <a href="/claude-code-docs-ko/permissions.html#working-directories">추가 작업 디렉토리</a> 내에 있는 한 이후 Bash 명령에 유지됩니다. 서브에이전트 세션은 작업 디렉토리 변경이 유지되지 않습니다. <ul><li><code>cd</code>가 해당 디렉토리 외부로 이동하면, Claude Code는 프로젝트 디렉토리로 재설정하고 도구 결과에 <code>Shell cwd was reset to &lt;dir&gt;</code>을 추가합니다.</li><li>이 유지 동작을 비활성화하여 모든 Bash 명령이 프로젝트 디렉토리에서 시작하게 하려면, <code>CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR=1</code>을 설정하세요.</li></ul></li><li>환경 변수는 지속되지 않습니다. 한 명령에서의 <code>export</code>는 다음 명령에서 사용할 수 없습니다.</li></ul><p>Claude Code를 시작하기 전에 virtualenv 또는 conda 환경을 활성화하세요. Bash 명령 전반에 걸쳐 환경 변수를 유지하려면, Claude Code를 시작하기 전에 <a href="/claude-code-docs-ko/env-vars.html"><code>CLAUDE_ENV_FILE</code></a>을 셸 스크립트로 설정하거나, <a href="/claude-code-docs-ko/hooks.html#persist-environment-variables">SessionStart 훅</a>을 사용하여 동적으로 설정하세요.</p><h2 id="lsp-도구-동작" tabindex="-1">LSP 도구 동작 <a class="header-anchor" href="#lsp-도구-동작" aria-label="Permalink to &quot;LSP 도구 동작&quot;">​</a></h2><p>LSP 도구는 실행 중인 언어 서버로부터 Claude에게 코드 인텔리전스를 제공합니다. 각 파일 편집 후 자동으로 타입 오류와 경고를 보고하여 Claude가 별도의 빌드 단계 없이 문제를 수정할 수 있게 합니다. Claude는 코드 탐색을 위해 직접 호출할 수도 있습니다:</p><ul><li>심볼 정의로 이동</li><li>심볼에 대한 모든 참조 찾기</li><li>특정 위치의 타입 정보 가져오기</li><li>파일 또는 워크스페이스의 심볼 나열</li><li>인터페이스 구현 찾기</li><li>호출 계층 추적</li></ul><p>이 도구는 언어용 <a href="/claude-code-docs-ko/discover-plugins.html#code-intelligence">코드 인텔리전스 플러그인</a>을 설치할 때까지 비활성 상태입니다. 플러그인에는 언어 서버 구성이 포함되어 있으며, 서버 바이너리는 별도로 설치합니다.</p><h2 id="monitor-도구" tabindex="-1">Monitor 도구 <a class="header-anchor" href="#monitor-도구" aria-label="Permalink to &quot;Monitor 도구&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Monitor 도구는 Claude Code v2.1.98 이상이 필요합니다.</p></div><p>Monitor 도구를 사용하면 Claude가 대화를 중단하지 않고 백그라운드에서 무언가를 감시하고 변경 시 반응할 수 있습니다. Claude에게 다음을 요청하세요:</p><ul><li>로그 파일을 추적하고 오류가 나타날 때 알림</li><li>PR 또는 CI 작업을 폴링하고 상태가 변경될 때 보고</li><li>파일 변경을 위한 디렉토리 감시</li><li>지정한 장기 실행 스크립트의 출력 추적</li></ul><p>Claude는 감시를 위한 작은 스크립트를 작성하고 백그라운드에서 실행하며, 도착하는 각 출력 줄을 수신합니다. 동일한 세션에서 계속 작업할 수 있으며 이벤트가 발생하면 Claude가 끼어듭니다. 모니터를 중지하려면 Claude에게 취소를 요청하거나 세션을 종료하세요.</p><p>Monitor는 <a href="/claude-code-docs-ko/permissions.html#tool-specific-permission-rules">Bash와 동일한 권한 규칙</a>을 사용하므로 Bash에 설정된 <code>allow</code> 및 <code>deny</code> 패턴이 여기에도 적용됩니다. Amazon Bedrock, Google Vertex AI, Microsoft Foundry에서는 사용할 수 없습니다. <code>DISABLE_TELEMETRY</code> 또는 <code>CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC</code>이 설정된 경우에도 사용할 수 없습니다.</p><h2 id="powershell-도구" tabindex="-1">PowerShell 도구 <a class="header-anchor" href="#powershell-도구" aria-label="Permalink to &quot;PowerShell 도구&quot;">​</a></h2><p>Windows에서 Claude Code는 Git Bash를 통해 라우팅하는 대신 PowerShell 명령을 네이티브로 실행할 수 있습니다. 이것은 옵트인 프리뷰입니다.</p><h3 id="powershell-도구-활성화" tabindex="-1">PowerShell 도구 활성화 <a class="header-anchor" href="#powershell-도구-활성화" aria-label="Permalink to &quot;PowerShell 도구 활성화&quot;">​</a></h3><p>환경 또는 <code>settings.json</code>에서 <code>CLAUDE_CODE_USE_POWERSHELL_TOOL=1</code>을 설정하세요:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;CLAUDE_CODE_USE_POWERSHELL_TOOL&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Claude Code는 <code>pwsh.exe</code> (PowerShell 7+)를 자동 감지하며 <code>powershell.exe</code> (PowerShell 5.1)로 대체합니다. Bash 도구는 PowerShell 도구와 함께 등록된 상태로 유지되므로, Claude에게 PowerShell을 사용하도록 요청해야 할 수 있습니다.</p><h3 id="설정-훅-스킬에서의-셸-선택" tabindex="-1">설정, 훅, 스킬에서의 셸 선택 <a class="header-anchor" href="#설정-훅-스킬에서의-셸-선택" aria-label="Permalink to &quot;설정, 훅, 스킬에서의 셸 선택&quot;">​</a></h3><p>PowerShell이 사용되는 위치를 제어하는 세 가지 추가 설정이 있습니다:</p><ul><li><a href="/claude-code-docs-ko/settings.html#available-settings"><code>settings.json</code></a>의 <code>&quot;defaultShell&quot;: &quot;powershell&quot;</code>: 대화형 <code>!</code> 명령을 PowerShell을 통해 라우팅합니다. PowerShell 도구가 활성화되어 있어야 합니다.</li><li>개별 <a href="/claude-code-docs-ko/hooks.html#command-hook-fields">명령 훅</a>의 <code>&quot;shell&quot;: &quot;powershell&quot;</code>: 해당 훅을 PowerShell에서 실행합니다. 훅은 PowerShell을 직접 생성하므로 <code>CLAUDE_CODE_USE_POWERSHELL_TOOL</code>과 무관하게 작동합니다.</li><li><a href="/claude-code-docs-ko/skills.html#frontmatter-reference">스킬 프론트매터</a>의 <code>shell: powershell</code>: <code>!\`command\`</code> 블록을 PowerShell에서 실행합니다. PowerShell 도구가 활성화되어 있어야 합니다.</li></ul><p>Bash 도구 섹션에서 설명한 것과 동일한 메인 세션 작업 디렉토리 재설정 동작이 PowerShell 명령에도 적용되며, <code>CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR</code> 환경 변수도 포함됩니다.</p><h3 id="프리뷰-제한-사항" tabindex="-1">프리뷰 제한 사항 <a class="header-anchor" href="#프리뷰-제한-사항" aria-label="Permalink to &quot;프리뷰 제한 사항&quot;">​</a></h3><p>PowerShell 도구는 프리뷰 기간 중 다음과 같은 알려진 제한 사항이 있습니다:</p><ul><li>Auto 모드는 아직 PowerShell 도구와 함께 작동하지 않습니다</li><li>PowerShell 프로파일이 로드되지 않습니다</li><li>샌드박싱이 지원되지 않습니다</li><li>네이티브 Windows에서만 지원되며, WSL은 지원되지 않습니다</li><li>Claude Code를 시작하려면 여전히 Git Bash가 필요합니다</li></ul><h2 id="사용-가능한-도구-확인" tabindex="-1">사용 가능한 도구 확인 <a class="header-anchor" href="#사용-가능한-도구-확인" aria-label="Permalink to &quot;사용 가능한 도구 확인&quot;">​</a></h2><p>정확한 도구 세트는 프로바이더, 플랫폼, 설정에 따라 다릅니다. 실행 중인 세션에서 로드된 내용을 확인하려면 Claude에게 직접 물어보세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What tools do you have access to?</span></span></code></pre></div><p>Claude가 대화 형식으로 요약을 제공합니다. 정확한 MCP 도구 이름은 <code>/mcp</code>를 실행하세요.</p><h2 id="참고-항목" tabindex="-1">참고 항목 <a class="header-anchor" href="#참고-항목" aria-label="Permalink to &quot;참고 항목&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>: 외부 서버를 연결하여 커스텀 도구 추가</li><li><a href="/claude-code-docs-ko/permissions.html">권한</a>: 권한 시스템, 규칙 구문, 도구별 패턴</li><li><a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>: 서브에이전트의 도구 접근 구성</li><li><a href="/claude-code-docs-ko/hooks-guide.html">훅</a>: 도구 실행 전후에 커스텀 명령 실행</li></ul>`,39)])])}const p=e(o,[["render",s]]);export{g as __pageData,p as default};
